(function ajouterQuestionsManuellesMANUAL_L3_SF_QUESTIONS() {
  if (!Array.isArray(window.QUIZ_QUESTIONS_QUIZ)) window.QUIZ_QUESTIONS_QUIZ = [];
  const existingIds = new Set(window.QUIZ_QUESTIONS_QUIZ.map((q) => q && q.id).filter(Boolean));
  for (const q of MANUAL_L3_SF_QUESTIONS) {
    if (!q || !q.id || existingIds.has(q.id)) continue;
    existingIds.add(q.id);
    window.QUIZ_QUESTIONS_QUIZ.push(q);
  }
})();
